class MockDatabase implements Database {
  private tables: Map<string, Map<number, unknown>> = new Map();

  async query<T = unknown>(sql: string, params: unknown[] = []): Promise<T[]> {
    const sqlLower = sql.toLowerCase().trim();
    if (sqlLower.startsWith('select')) return this.handleSelect<T>(sql);
    if (sqlLower.startsWith('insert')) return this.handleInsert<T>(sql, params);
    return [] as T[];
  }
}

export function createDatabase(config?: { mock?: boolean }): Database {
  if (config?.mock !== false) {
    return new MockDatabase();
  }
  throw new Error('Production database not implemented');
}

